UPDATE t_car_cost_cash_pay
SET waybill_id = #{waybillId}
WHERE cash_pay_id = #{cashPayId}

mapper.select:
SELECT ROUND(IFNULL(SUM(Amount), 0), 4)
FROM t_car_cost_cash_pay
WHERE waybill_id = #{waybillId} AND audit_status = #{auditStatus}

SELECT *
FROM t_car_cost_cash_pay
WHERE waybill_id in

    #{item}

and audit_status = #{auditStatus}

SELECT
    cccp.vehicle_id,
    SUM(cccp.amount) amount
FROM t_car_cost_cash_pay cccp
LEFT JOIN t_waybill w ON w.waybill_id = cccp.waybill_id
where DATE_FORMAT(w.create_time, '%Y-%m-%d') >= #{queryForm.startTime}
AND DATE_FORMAT(w.create_time, '%Y-%m-%d') <= #{queryForm.endTime}
and cccp.enterprise_id = #{queryForm.enterpriseId}
and cccp.vehicle_id in

    #{item}

GROUP BY cccp.vehicle_id

SELECT cccp.*, cct.tabulation_id, cct.module_id, cct.module_type, w.waybill_number, w.container_number, v.vehicle_number, d.driver_name, ccc.cost_type, ccc.category_name FROM t_car_cost_tabulation cct LEFT JOIN t_waybill w ON cct.waybill_id = w.waybill_id LEFT JOIN t_vehicle v ON cct.vehicle_id = v.vehicle_id LEFT JOIN t_driver d ON cct.driver_id = d.driver_id LEFT JOIN t_car_cost_category ccc ON cct.category_id = ccc.category_id LEFT JOIN t_car_cost_cash_pay cccp ON cct.module_id = cccp.cash_pay_id
cct.tabulation_id IN
#{item}
